const body = $input.first().json.body || {};
const program_name = (body.program_name || '').toUpperCase().trim();
if (!program_name) throw new Error('program_name es requerido');
return { json: { program_name } };

const prog       = $('Busca Programa').first().json;
const existingTypes = $('Fetch Finding Types').all().map(i => i.json);

const existingTypesText = existingTypes.length > 0
  ? 'TIPOS DE HALLAZGO YA EXISTENTES (reutizalos cuando aplique):\n' +
    existingTypes.map(t => `- ${t.code} | ${t.name} | severidad: ${t.default_severity}`).join('\n')
  : 'No hay tipos previos. Creá los que necesites.';

const knownTypes = `TIPOS CONOCIDOS DE ANTI-PATRONES COBOL (usá estos códigos si aplican):
- GOTO_USAGE | Uso de GO TO | CRITICAL
- HARDCODED_VALUE | Valor literal hardcodeado | WARNING
- MISSING_ERROR_HANDLING | Falta manejo de errores en I/O o SQL | CRITICAL
- DEAD_CODE | Código inalcanzable | WARNING
- DEEP_NESTING | Anidamiento excesivo de PERFORMs | WARNING
- MAGIC_NUMBER | Número sin nombre simbólico | INFO
- POOR_PARAGRAPH_NAMING | Nombre de párrafo poco descriptivo | INFO
- MISSING_COMMENTS | Falta de documentación/comentarios | INFO
- LARGE_PARAGRAPH | Párrafo excesivamente largo (+50 líneas) | WARNING
- SQL_NO_CHECK | SQL sin verificación de SQLCODE | CRITICAL
- FILE_NOT_CLOSED | Archivo no cerrado explícitamente | CRITICAL
- DUPLICATED_CODE | Código duplicado o repetido | WARNING
- COMPLEX_CONDITION | Condición lógica excesivamente compleja | WARNING
- OBSOLETE_VERB | Uso de verbo COBOL obsoleto | INFO
- GLOBAL_VAR_OVERUSE | Exceso de variables globales en WORKING-STORAGE | WARNING`;

const prompt = `Sos un experto en auditoría de código COBOL mainframe.
Analizá el siguiente programa COBOL en busca de anti-patrones, malas prácticas y problemas de calidad.

PROGRAMA: ${prog.program_name} (${prog.program_type})
LÍNEAS TOTALES: ${prog.line_count} | LÍNEAS DE CÓDIGO: ${prog.clean_line_count}

${existingTypesText}

${knownTypes}

CÓDIGO FUENTE COMPLETO:
\`\`\`cobol
${prog.original_code}
\`\`\`

Retorná EXCLUSIVAMENTE un JSON válido con esta estructura (sin markdown, sin texto adicional):
{
  "summary": "resumen ejecutivo de la calidad del código en 2-3 oraciones",
  "overall_quality": "POOR|FAIR|GOOD|EXCELLENT",
  "findings": [
    {
      "type_code": "GOTO_USAGE",
      "type_name": "Uso de GO TO",
      "type_description": "descripción del tipo de anti-patrón",
      "type_default_severity": "CRITICAL",
      "severity": "CRITICAL",
      "title": "título específico del hallazgo",
      "description": "explicación detallada del problema y su impacto",
      "line_number": 42,
      "line_content": "           GO TO END-PROGRAM.",
      "raw_evidence": "contexto de 3-5 líneas alrededor del hallazgo"
    }
  ]
}

REGLAS:
- Incluí TODOS los hallazgos encontrados (no limites la cantidad)
- line_number y line_content son opcionales; ponelos a null si no aplica
- Los únicos valores válidos para severity y type_default_severity son: CRITICAL, WARNING, INFO
- severity puede diferir de type_default_severity si el contexto lo justifica
- Si no hay hallazgos, retorná findings como array vacío
- El JSON debe ser parseable directamente con JSON.parse()`;

return {
  json: {
    prompt,
    program_name: prog.program_name,
    version_id: prog.version_id,
    run_id: $('Crea Audit Run').first().json.run_id
  }
};

const chainOut = $input.first().json;
const ctx      = $('Prepara Prompt').first().json;

let text = (chainOut.text || chainOut.output || '').trim();
text = text.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '').trim();

let parsed;
try {
  parsed = JSON.parse(text);
} catch(e) {
  throw new Error('LLM no retornó JSON válido. Fragmento: ' + text.slice(0, 300));
}

const findings = parsed.findings || [];

if (findings.length === 0) {
  return [{
    json: {
      _no_findings: true,
      audit_run_id: ctx.run_id,
      version_id: ctx.version_id,
      program_name: ctx.program_name,
      summary: parsed.summary || 'Sin hallazgos detectados.',
      overall_quality: parsed.overall_quality || 'GOOD',
      findings_count: 0
    }
  }];
}

const VALID_SEV = ['CRITICAL', 'WARNING', 'INFO'];
const SEV_MAP   = { HIGH: 'CRITICAL', MEDIUM: 'WARNING', LOW: 'INFO' };
const mapSev = v => {
  const u = (v || '').toUpperCase();
  if (VALID_SEV.includes(u)) return u;
  return SEV_MAP[u] || 'WARNING';
};

return findings.map(f => ({
  json: {
    _no_findings: false,
    audit_run_id: ctx.run_id,
    version_id:   ctx.version_id,
    program_name: ctx.program_name,
    summary:      parsed.summary || '',
    overall_quality: parsed.overall_quality || 'UNKNOWN',
    // Tipo de hallazgo
    type_code:             (f.type_code || 'UNKNOWN_ISSUE').toUpperCase().replace(/\s+/g,'_').slice(0,50),
    type_name:             (f.type_name || f.type_code || 'Unknown Issue').slice(0,100),
    type_description:      f.type_description || '',
    type_default_severity: mapSev(f.type_default_severity),
    // Instancia del hallazgo
    severity:     mapSev(f.severity),
    title:        (f.title || '').slice(0, 255),
    description:  f.description || '',
    line_number:  f.line_number ? parseInt(f.line_number) : null,
    line_content: f.line_content || null,
    raw_evidence: f.raw_evidence || null
  }
}));

// Parea el id retornado por el upsert con los datos del hallazgo original.
// n8n preserva el orden de items, así que el índice es confiable.
const typeResults  = $input.all();
const findingItems = $('Parsea Findings').all().filter(i => !i.json._no_findings);

return typeResults.map((item, idx) => {
  const f = findingItems[idx].json;
  return {
    json: {
      finding_type_id:   item.json.id,
      audit_run_id:      f.audit_run_id,
      version_id:        f.version_id,
      finding_severity:  f.severity,
      title:             f.title,
      finding_description: f.description,
      line_number:       f.line_number,
      line_content:      f.line_content,
      raw_evidence:      f.raw_evidence
    }
  };
});

const all         = $input.all();
const first       = $('Parsea Findings').first().json;
const no_findings = first._no_findings === true;
const findings_count = no_findings ? 0 : all.length;

return {
  json: {
    audit_run_id:    first.audit_run_id,
    program_name:    first.program_name,
    findings_count,
    summary:         first.summary,
    overall_quality: first.overall_quality
  }
};

const data = $('Cuenta y Cierra').first().json;
return {
  json: {
    success:         true,
    program_name:    data.program_name,
    audit_run_id:    data.audit_run_id,
    findings_count:  data.findings_count,
    overall_quality: data.overall_quality,
    summary:         data.summary
  }
};

